mapper.select:
SELECT id, name, document_type, form_fields::text AS form_fields, created_at
FROM gw_approval_templates
WHERE id = #{id}

SELECT d.id, d.template_id, d.document_type, d.title, d.content, d.form_data::text AS form_data, d.status, d.applicant_id, d.created_at, d.submitted_at, d.completed_at, d.rejection_reason, u.name AS applicant_name, t.name AS template_name, (SELECT COUNT(*) FROM gw_approval_lines WHERE document_id = d.id) AS total_lines, (SELECT COUNT(*) FROM gw_approval_lines WHERE document_id = d.id AND status = 'APPROVED') AS approved_lines FROM gw_approval_documents d JOIN itsm_users u ON d.applicant_id = u.id LEFT JOIN gw_approval_templates t ON d.template_id = t.id
AND EXISTS ( SELECT 1 FROM gw_approval_lines WHERE document_id = d.id AND approver_id = #{userId} )
AND d.applicant_id = #{userId}
AND d.status = #{status}
ORDER BY d.created_at DESC

mapper.update:
UPDATE gw_approval_documents
SET status = #{status}
    , submitted_at = #{submittedAt}
    , completed_at = #{completedAt}
    , rejection_reason = #{rejectionReason}
WHERE id = #{id}

UPDATE gw_approval_lines
SET status = #{status},
    comment = #{comment},
    approved_at = #{approvedAt}
WHERE id = #{id}
